// Aggregate everything into a Claude-ready context. Output a single
// item with `briefing_context` (compact JSON) + `payload` (the
// Anthropic request body) so the next node can POST it directly.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};

const alerts     = allOf('Open Alerts 24h');
const costs7d    = allOf('Costs 7d');
const budgets    = allOf('Budgets');
const breakers   = allOf('Workflow Breakers');
const leads24    = allOf('Leads 24h');
const books24    = allOf('Bookings 24h');
const driftRuns  = allOf('Latest Drift Run');
const latestDrift = driftRuns[0] || null;

// Compute yesterday vs 7-day avg spend per service
const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
const byService = {};
costs7d.forEach(function (r) {
  if (!r || !r.service_name) return;
  if (!byService[r.service_name]) byService[r.service_name] = { yesterday: 0, total: 0, days: 0 };
  byService[r.service_name].total += Number(r.spend_cents || 0);
  byService[r.service_name].days += 1;
  if (r.tracking_date === yesterday) byService[r.service_name].yesterday += Number(r.spend_cents || 0);
});
const spendSummary = Object.keys(byService).map(function (svc) {
  const s = byService[svc];
  const avg = s.days > 0 ? s.total / s.days : 0;
  const delta = avg > 0 ? Math.round(((s.yesterday - avg) / avg) * 100) : 0;
  const budget = budgets.find(function (b) { return b && b.service_name === svc; });
  return {
    service: svc,
    yesterday_cents: s.yesterday,
    seven_day_avg_cents: Math.round(avg),
    delta_pct: delta,
    daily_limit_cents: budget ? budget.daily_limit_cents : null,
    monthly_limit_cents: budget ? budget.monthly_limit_cents : null
  };
});

// Lead activity
const leadsByStatus = {};
leads24.forEach(function (l) {
  const s = (l && l.lead_status) || 'unknown';
  leadsByStatus[s] = (leadsByStatus[s] || 0) + 1;
});
const leadsBySource = {};
leads24.forEach(function (l) {
  const s = (l && l.source) || 'unknown';
  leadsBySource[s] = (leadsBySource[s] || 0) + 1;
});

// Alerts by severity
const alertsBySeverity = {};
alerts.forEach(function (a) {
  const s = (a && a.severity) || 'info';
  alertsBySeverity[s] = (alertsBySeverity[s] || 0) + 1;
});

// Compose the context object Claude reads
const context = {
  date: new Date().toISOString().slice(0, 10),
  alerts: {
    total_open: alerts.length,
    by_severity: alertsBySeverity,
    top_5: alerts.slice(0, 5).map(function (a) {
      return { severity: a.severity, title: a.title, module: a.module_name, when: a.triggered_at };
    })
  },
  costs: { per_service: spendSummary },
  workflow_breakers: {
    total_paused: breakers.length,
    list: breakers.slice(0, 10).map(function (b) {
      return { workflow: b.workflow_name || b.workflow_id, status: b.current_status, reason: b.paused_reason };
    })
  },
  activity_24h: {
    new_leads: leads24.length,
    new_bookings: books24.length,
    leads_by_status: leadsByStatus,
    leads_by_source: leadsBySource
  },
  workflow_drift: latestDrift ? {
    ran_at: latestDrift.ran_at,
    total: latestDrift.drift_count,
    repo_only: latestDrift.repo_only,
    n8n_only: latestDrift.n8n_only,
    content_diff: latestDrift.content_diff,
    active_diff: latestDrift.active_diff
  } : { ran_at: null, total: 0, repo_only: 0, n8n_only: 0, content_diff: 0, active_diff: 0 }
};

const systemPrompt = [
  'You are the Crystallux DevOps Digital Employee. Every morning at 7 AM Mary reads your briefing.',
  '',
  'Write a single, calm, scannable paragraph (max 180 words) covering:',
  '1. Overall health verdict in the first sentence (green / yellow / red + WHY).',
  '2. Anything urgent (critical alerts, tripped breakers, budget overages, workflow drift). Name the specific service or workflow.',
  '3. Yesterday\'s activity in plain numbers (new leads, bookings, notable spend).',
  '4. If workflow_drift.total is non-zero, mention it briefly + suggest running auto-reship-drift.sh when high.',
  '5. One concrete next action for Mary, OR "nothing requires you today" if truly quiet.',
  '',
  'Voice: senior on-call engineer briefing the founder. Direct. No hedging. No marketing language. No em-dashes (use periods or line breaks). First-person plural only when describing system actions ("we paused X"); never "I think...".',
  '',
  'If the numbers are zero or everything is quiet, say so plainly — do not invent urgency.'
].join('\n');

const userPrompt = 'Here is the platform state for ' + context.date + '. Write the daily DevOps briefing.\n\n' + JSON.stringify(context, null, 2);

return { json: {
  briefing_context: context,
  payload: {
    model: 'claude-sonnet-4-6',
    max_tokens: 700,
    system: systemPrompt,
    messages: [ { role: 'user', content: userPrompt } ]
  }
} };

// Parse Claude response, build the Postmark email + the sentinel_alerts row.
const r = $input.item.json;
const ctx = $('Shape Briefing Context').first().json.briefing_context;

let briefing = '';
if (r && Array.isArray(r.content)) {
  const tb = r.content.find(function (b) { return b && b.type === 'text'; });
  briefing = tb ? tb.text : '';
}
if (!briefing) {
  // Fallback: minimal mechanical briefing so an email always lands
  briefing = 'Platform briefing for ' + ctx.date + '. New leads in last 24h: ' + ctx.activity_24h.new_leads + '. New bookings: ' + ctx.activity_24h.new_bookings + '. Open alerts: ' + ctx.alerts.total_open + '. Paused workflows: ' + ctx.workflow_breakers.total_paused + '. Claude API did not respond cleanly so this is a fallback summary.';
}

// HTML wrapper for the email
const htmlBody = '<div style="font-family:Arial,Helvetica,sans-serif;font-size:15px;line-height:1.6;color:#0f172a;max-width:640px;">' +
  '<div style="padding:20px 24px;background:linear-gradient(135deg,#0f4c81 0%,#1a6fa5 100%);color:#fff;border-radius:8px 8px 0 0;">' +
    '<div style="font-size:12px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;opacity:0.85;">Crystallux DevOps</div>' +
    '<div style="font-size:22px;font-weight:800;margin-top:6px;">Morning briefing &middot; ' + ctx.date + '</div>' +
  '</div>' +
  '<div style="padding:24px;background:#fff;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 8px 8px;">' +
    '<p style="margin:0 0 16px;white-space:pre-wrap;">' + briefing.replace(/</g, '&lt;') + '</p>' +
    '<table style="width:100%;border-collapse:collapse;font-size:13px;margin-top:8px;">' +
      '<tr><td style="padding:6px 0;color:#64748b;">New leads (24h)</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + ctx.activity_24h.new_leads + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">New bookings (24h)</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + ctx.activity_24h.new_bookings + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">Open alerts</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + ctx.alerts.total_open + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">Paused workflows</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + ctx.workflow_breakers.total_paused + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">Workflow drift (repo vs n8n)</td><td style="padding:6px 0;text-align:right;font-weight:700;color:' + ((ctx.workflow_drift && ctx.workflow_drift.total > 10) ? '#dc2626' : '#0f172a') + ';">' + (ctx.workflow_drift ? ctx.workflow_drift.total : 0) + '</td></tr>' +
    '</table>' +
    '<div style="margin-top:20px;font-size:11px;color:#94a3b8;">Open the Sentinel dashboard for full detail: <a href="https://admin.crystallux.org/pages/sentinel.html" style="color:#0f4c81;">admin.crystallux.org/pages/sentinel</a></div>' +
  '</div>' +
  '</div>';

const maryEmail = $env.MARY_EMAIL || 'adesholaakintunde@gmail.com';
const fromAddr  = $env.POSTMARK_FROM || 'mary@crystallux.org';

return { json: {
  briefing_text: briefing,
  briefing_context: ctx,
  postmark_payload: {
    From: fromAddr,
    To: maryEmail,
    Subject: 'DevOps briefing for ' + ctx.date + ' — ' + (ctx.alerts.total_open > 0 ? ctx.alerts.total_open + ' open alert' + (ctx.alerts.total_open === 1 ? '' : 's') : 'all clear'),
    HtmlBody: htmlBody,
    TextBody: briefing,
    MessageStream: 'outbound'
  },
  sentinel_alert_row: {
    module_name: 'devops',
    alert_type: 'daily_briefing',
    severity: ctx.alerts.by_severity.critical ? 'warning' : 'info',
    title: 'DevOps daily briefing — ' + ctx.date,
    message: briefing.slice(0, 1500),
    details: { briefing_context: ctx },
    status: 'resolved',
    aggregation_key: 'devops:daily:' + ctx.date
  }
} };
